select
  s.id, 'board', NULL, 'Resident ถามอาจารย์เรื่อง pharmacology — teratogenic medications + FDA pregnancy category', '[{"label":"A","text":"All drugs safe in pregnancy"},{"label":"B","text":"Teratogenic Medications + Pregnancy Considerations: (1) FDA categories replaced by PLLR (Pregnancy and Lactation Labeling Rule) — narrative risk; (2) Known teratogens to avoid: ACEi/ARB (renal dysgenesis, oligohydramnios 2nd-3rd trimester), warfarin (6-12 wk window — chondrodysplasia, microcephaly, fetal bleeding throughout), isotretinoin (multiple), valproic acid (NTD, autism, low IQ), phenytoin (fetal hydantoin syndrome), carbamazepine (NTD), lithium (Ebstein anomaly — relative risk), methotrexate (multiple), thalidomide (limb), DES (clear cell adenocarcinoma in offspring), tetracycline (tooth, bone), aminoglycosides (ototoxicity), fluconazole (multiple), live vaccines (theoretical, avoid), androgens, NSAIDs (avoid 3rd trimester — ductus arteriosus closure, oligohydramnios); (3) Generally safer alternatives: penicillins, cephalosporins (most), acetaminophen, methyldopa (HT), labetalol (HT), nifedipine (HT, tocolysis), insulin (DM), heparin/LMWH (anticoagulation), levothyroxine (hypothyroid); (4) Timing matters — organogenesis 3-8 weeks most vulnerable; (5) Risk-benefit individualized — uncontrolled disease may harm more than medication; (6) Resources: REPROTOX, TERIS, OTIS/MotherToBaby; (7) Folate before + during pregnancy (NTD prevention); (8) Pre-conception counseling for chronic conditions"},{"label":"C","text":"No need for caution"},{"label":"D","text":"All antibiotics safe"},{"label":"E","text":"Stop all medications"}]'::jsonb,
  'B', 'Teratogen awareness critical. Major: ACEi/ARB, warfarin, isotretinoin, valproate, thalidomide, methotrexate. Generally safer: penicillins, acetaminophen, methyldopa, labetalol, insulin, heparin, levothyroxine. Timing of exposure matters. Risk-benefit individualized. Resources: REPROTOX, TERIS, OTIS. Pre-conception counseling + medication review. Folate pre-conception NTD prevention.', NULL,
  'medium', 'obgyn', 'review',
  'ob_gyn', 'basic_science', 'obgyn', 'adult',
  'FDA Pregnancy and Lactation Labeling Rule (PLLR); REPROTOX; TERIS', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_basic_science'
  and s.audience = 'board'
