select
  s.id, 'board', NULL, 'Hospital implements ortho-geriatric co-management for hip fracture patients — reduce mortality + complications', '[{"label":"A","text":"Single specialty manages"},{"label":"B","text":"Ortho-Geriatric Co-Management for Hip Fracture: (1) **Co-management model**: ortho + geriatrics jointly manage, daily ward rounds; (2) **Evidence**: reduces mortality (10-15% relative), LOS, complications, delirium per Cochrane + systematic reviews; (3) **Care pathway**: standardized + multidisciplinary — admission within hours, surgical assessment + repair within 24-48h, post-op early mobilization day 1; (4) **Pre-op optimization**: anesthesia evaluation, anti-coagulation reversal, cardiac risk assessment + optimization (echo, beta-blocker, statin), nutrition, anemia treatment, delirium assessment + prevention; (5) **Pain control**: multimodal — fascia iliaca compartment block or femoral nerve block effective + opioid-sparing; (6) **VTE prophylaxis**: low molecular weight heparin or DOAC; (7) **Delirium**: CAM screening, prevention (reorient, hydrate, mobilize, sleep), treatment of underlying causes; (8) **Pressure injury prevention**: turning, special mattress, nutrition, skin care; (9) **Nutrition**: oral supplement (Cochrane evidence reduces complications), early diet, PEG if needed; (10) **Mobilization day 1**: weight-bearing as tolerated (essential — Cochrane), PT/OT, fall prevention; (11) **Discharge planning early**: home vs rehab vs SNF, family support, services; (12) **Secondary prevention**: osteoporosis treatment, fall prevention, FLS; (13) **Quality metrics**: 30-day mortality, time to surgery, delirium incidence, mobilization day, LOS, readmission, secondary prevention rates; (14) **NSQIP, Australia + UK National Hip Fracture Database, AAOS — best practice models"},{"label":"C","text":"Avoid surgery"},{"label":"D","text":"Geriatric alone"},{"label":"E","text":"Bedrest"}]'::jsonb,
  'B', 'Ortho-geriatric co-management for hip fracture: evidence-based — reduces mortality + complications. Joint care, standardized pathway, early surgery, multimodal pain, delirium prevention, early mobilization, secondary prevention. UK National Hip Fracture Database transformed UK practice. AAOS standards. Quality metrics drive improvement.', NULL,
  'easy', 'trauma', 'review',
  'orthopedics', 'ems_mgmt', 'trauma', 'adult',
  'UK National Hip Fracture Database; Cochrane Reviews; AAOS Hip Fracture Guidelines', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
